# [FCP2] Agent-Side Caching: ETag and Cache-Control Support

## Goal
Enable efficient agent-side caching of discovery and introspection responses to reduce latency and host load.

## Problem
Agents frequently call discovery/introspect endpoints to get connector and tool information. Currently:
- Every call hits the host even if nothing changed
- No way for agents to know if their cached data is stale
- Wastes resources re-fetching identical data

## Solution: HTTP Caching Semantics for JSON-RPC

### Response Headers (Extension)

Add optional cache metadata to JSON-RPC responses:

```jsonc
{
  "jsonrpc": "2.0",
  "id": 1,
  "result": {
    "connectors": [...],
    "_meta": {
      "cache": {
        "etag": "\"abc123def456\"",
        "last_modified": "2026-01-22T18:00:00Z",
        "max_age_seconds": 300,
        "stale_while_revalidate_seconds": 60
      }
    }
  }
}
```

### Conditional Request Support

Agents can include cache validators in requests:

```jsonc
{
  "jsonrpc": "2.0",
  "id": 1,
  "method": "connectors/discover",
  "params": {
    "_cache": {
      "if_none_match": "\"abc123def456\"",
      "if_modified_since": "2026-01-22T18:00:00Z"
    }
  }
}
```

### 304 Not Modified Response

If cache is still valid, host returns a lightweight response:

```jsonc
{
  "jsonrpc": "2.0",
  "id": 1,
  "result": {
    "_meta": {
      "status": 304,
      "message": "Not Modified",
      "cache": {
        "etag": "\"abc123def456\"",
        "max_age_seconds": 300
      }
    }
  }
}
```

### Implementation

```rust
pub struct CacheMetadata {
    /// Strong ETag for content comparison
    pub etag: String,
    /// Last modification timestamp
    pub last_modified: DateTime<Utc>,
    /// Seconds before client should revalidate
    pub max_age_seconds: u32,
    /// Seconds to serve stale while revalidating
    pub stale_while_revalidate_seconds: Option<u32>,
}

pub struct CacheValidator {
    pub if_none_match: Option<String>,
    pub if_modified_since: Option<DateTime<Utc>>,
}

impl DiscoveryEndpoint {
    pub async fn discover_with_cache(
        &self,
        filter: Option<DiscoveryFilter>,
        validator: Option<CacheValidator>,
    ) -> DiscoveryResponse {
        // Check if registry has changed
        let current_etag = self.registry.content_hash();
        let current_modified = self.registry.last_modified();

        if let Some(v) = validator {
            // Check ETag match
            if let Some(client_etag) = v.if_none_match {
                if client_etag == current_etag {
                    return DiscoveryResponse::not_modified(current_etag);
                }
            }
            // Check modification time
            if let Some(client_modified) = v.if_modified_since {
                if current_modified <= client_modified {
                    return DiscoveryResponse::not_modified(current_etag);
                }
            }
        }

        // Fetch fresh data
        let connectors = self.registry.list_filtered(filter).await;
        DiscoveryResponse {
            connectors,
            cache: CacheMetadata {
                etag: current_etag,
                last_modified: current_modified,
                max_age_seconds: 300,
                stale_while_revalidate_seconds: Some(60),
            },
        }
    }
}

/// ETag generation for registry content
impl ConnectorRegistry {
    pub fn content_hash(&self) -> String {
        use sha2::{Sha256, Digest};
        let mut hasher = Sha256::new();

        // Hash all connector summaries
        for connector in self.connectors.values() {
            hasher.update(connector.id.as_bytes());
            hasher.update(connector.version.to_string().as_bytes());
            hasher.update(&[connector.enabled as u8]);
        }

        format!("\"{}\"", hex::encode(&hasher.finalize()[..8]))
    }

    pub fn last_modified(&self) -> DateTime<Utc> {
        self.connectors.values()
            .map(|c| c.installed_at)
            .max()
            .unwrap_or(self.created_at)
    }
}
```

### Cacheable Endpoints

| Method | Recommended max_age | ETag Source |
|--------|---------------------|-------------|
| `connectors/discover` | 5 min | Registry content hash |
| `connectors/introspect` | 15 min | Connector version + config |
| `host/capabilities` | 1 hour | Host version |
| `tools/list` | 5 min | Tool registry hash |

### Tests

```rust
#[tokio::test]
async fn test_discover_returns_cache_metadata() {
    let host = TestHost::new().await;
    host.install_connector("test-echo").await;

    let response = host.discover(None, None).await.unwrap();
    assert!(!response.cache.etag.is_empty());
    assert!(response.cache.max_age_seconds > 0);
}

#[tokio::test]
async fn test_conditional_request_returns_304() {
    let host = TestHost::new().await;
    host.install_connector("test-echo").await;

    // First request - get ETag
    let r1 = host.discover(None, None).await.unwrap();
    let etag = r1.cache.etag.clone();

    // Conditional request with same ETag
    let validator = CacheValidator { if_none_match: Some(etag), if_modified_since: None };
    let r2 = host.discover(None, Some(validator)).await.unwrap();

    assert_eq!(r2.meta.status, 304);
    assert!(r2.connectors.is_none()); // No body on 304
}

#[tokio::test]
async fn test_etag_changes_on_registry_update() {
    let host = TestHost::new().await;
    host.install_connector("test-echo").await;

    let r1 = host.discover(None, None).await.unwrap();
    let etag1 = r1.cache.etag.clone();

    // Install another connector
    host.install_connector("test-streaming").await;

    let r2 = host.discover(None, None).await.unwrap();
    assert_ne!(r1.cache.etag, r2.cache.etag);
}

#[tokio::test]
async fn test_stale_etag_returns_fresh_data() {
    let host = TestHost::new().await;
    host.install_connector("test-echo").await;

    let r1 = host.discover(None, None).await.unwrap();
    let old_etag = r1.cache.etag.clone();

    // Modify registry
    host.install_connector("test-streaming").await;

    // Conditional request with stale ETag
    let validator = CacheValidator { if_none_match: Some(old_etag), if_modified_since: None };
    let r2 = host.discover(None, Some(validator)).await.unwrap();

    assert_ne!(r2.meta.status, 304);
    assert_eq!(r2.connectors.as_ref().unwrap().len(), 2);
}

#[tokio::test]
async fn test_if_modified_since_validation() {
    let host = TestHost::new().await;
    host.install_connector("test-echo").await;

    let r1 = host.discover(None, None).await.unwrap();
    let last_modified = r1.cache.last_modified;

    // Request with if-modified-since after last modification
    let validator = CacheValidator {
        if_none_match: None,
        if_modified_since: Some(last_modified + Duration::seconds(1)),
    };
    let r2 = host.discover(None, Some(validator)).await.unwrap();

    assert_eq!(r2.meta.status, 304);
}
```

## Acceptance Criteria
- [ ] Discovery responses include ETag and Last-Modified
- [ ] Conditional requests with If-None-Match return 304 when unchanged
- [ ] Conditional requests with If-Modified-Since work correctly
- [ ] ETags change when registry content changes
- [ ] Cache headers are configurable per endpoint
- [ ] Stale-while-revalidate is supported for background refresh
- [ ] Documentation explains caching semantics for agent developers

# TEST: fcp-crypto Unit Tests (COSE, Ed25519, AEAD, HKDF, Shamir)

## Goal
Comprehensive test coverage for the fcp-crypto crate ensuring all cryptographic primitives
are correctly implemented with golden vectors from official test suites.

## Test Categories

### 1. COSE_Sign1 Tests

```rust
#[cfg(test)]
mod cose_tests {
    use fcp_crypto::cose::{CoseSign1, CoseKey, Algorithm};
    use fcp_crypto::ed25519::Ed25519KeyPair;

    #[test]
    fn test_cose_sign1_roundtrip() {
        let keypair = Ed25519KeyPair::generate();
        let payload = b"Hello, FCP\!";

        let signed = CoseSign1::sign(payload, &keypair, Algorithm::EdDSA).unwrap();
        let verified = signed.verify(&keypair.public_key()).unwrap();

        assert_eq\!(verified.payload, payload);
    }

    #[test]
    fn test_cose_sign1_invalid_signature_rejected() {
        let keypair1 = Ed25519KeyPair::generate();
        let keypair2 = Ed25519KeyPair::generate();
        let payload = b"Secret data";

        let signed = CoseSign1::sign(payload, &keypair1, Algorithm::EdDSA).unwrap();

        // Verify with wrong key should fail
        let result = signed.verify(&keypair2.public_key());
        assert\!(result.is_err());
    }

    #[test]
    fn test_cose_sign1_tampered_payload_rejected() {
        let keypair = Ed25519KeyPair::generate();
        let payload = b"Original payload";

        let mut signed = CoseSign1::sign(payload, &keypair, Algorithm::EdDSA).unwrap();

        // Tamper with payload
        signed.payload[0] ^= 0xFF;

        let result = signed.verify(&keypair.public_key());
        assert\!(result.is_err());
    }

    #[test]
    fn test_cose_sign1_rfc8152_vectors() {
        // Test against RFC 8152 Appendix C test vectors
        // https://datatracker.ietf.org/doc/html/rfc8152#appendix-C
        let vector = include_bytes\!("../tests/vectors/cose/rfc8152_sign1_vector.cbor");
        let expected_pk = hex::decode("...").unwrap();

        let signed = CoseSign1::from_cbor(vector).unwrap();
        let pk = CoseKey::from_bytes(&expected_pk).unwrap();
        assert\!(signed.verify(&pk).is_ok());
    }
}
```

### 2. Ed25519 Tests

```rust
#[cfg(test)]
mod ed25519_tests {
    use fcp_crypto::ed25519::{Ed25519KeyPair, Ed25519PublicKey, Ed25519Signature};

    #[test]
    fn test_ed25519_sign_verify() {
        let keypair = Ed25519KeyPair::generate();
        let message = b"Test message for signing";

        let signature = keypair.sign(message);
        assert\!(keypair.public_key().verify(message, &signature).is_ok());
    }

    #[test]
    fn test_ed25519_wycheproof_vectors() {
        // Test against Wycheproof test vectors
        let vectors: Vec<TestVector> = serde_json::from_str(
            include_str\!("../tests/vectors/ed25519/wycheproof.json")
        ).unwrap();

        for v in vectors {
            let pk = Ed25519PublicKey::from_bytes(&v.public_key).unwrap();
            let sig = Ed25519Signature::from_bytes(&v.signature).unwrap();

            let result = pk.verify(&v.message, &sig);
            assert_eq\!(result.is_ok(), v.expected_valid,
                "Vector {} failed: expected {}", v.tc_id, v.expected_valid);
        }
    }

    #[test]
    fn test_ed25519_deterministic() {
        let keypair = Ed25519KeyPair::generate();
        let message = b"Deterministic signing test";

        let sig1 = keypair.sign(message);
        let sig2 = keypair.sign(message);

        // Ed25519 signatures are deterministic (no randomness)
        assert_eq\!(sig1.to_bytes(), sig2.to_bytes());
    }

    #[test]
    fn test_ed25519_key_serialization() {
        let keypair = Ed25519KeyPair::generate();

        let pk_bytes = keypair.public_key().to_bytes();
        assert_eq\!(pk_bytes.len(), 32);

        let pk_restored = Ed25519PublicKey::from_bytes(&pk_bytes).unwrap();
        assert_eq\!(keypair.public_key().to_bytes(), pk_restored.to_bytes());
    }
}
```

### 3. AEAD Tests (ChaCha20-Poly1305 + AES-GCM)

```rust
#[cfg(test)]
mod aead_tests {
    use fcp_crypto::aead::{Aead, AeadAlgorithm, Nonce};

    #[test]
    fn test_chacha20poly1305_roundtrip() {
        let key = [0u8; 32];
        let nonce = Nonce::generate();
        let plaintext = b"Secret message";
        let aad = b"Additional data";

        let aead = Aead::new(AeadAlgorithm::ChaCha20Poly1305, &key).unwrap();

        let ciphertext = aead.seal(&nonce, plaintext, aad).unwrap();
        let decrypted = aead.open(&nonce, &ciphertext, aad).unwrap();

        assert_eq\!(decrypted, plaintext);
    }

    #[test]
    fn test_aead_tampered_ciphertext_rejected() {
        let key = [0u8; 32];
        let nonce = Nonce::generate();
        let plaintext = b"Original";
        let aad = b"";

        let aead = Aead::new(AeadAlgorithm::ChaCha20Poly1305, &key).unwrap();
        let mut ciphertext = aead.seal(&nonce, plaintext, aad).unwrap();

        // Tamper with ciphertext
        ciphertext[0] ^= 0xFF;

        let result = aead.open(&nonce, &ciphertext, aad);
        assert\!(result.is_err());
    }

    #[test]
    fn test_aead_wrong_aad_rejected() {
        let key = [0u8; 32];
        let nonce = Nonce::generate();
        let plaintext = b"Message";
        let aad = b"Correct AAD";

        let aead = Aead::new(AeadAlgorithm::ChaCha20Poly1305, &key).unwrap();
        let ciphertext = aead.seal(&nonce, plaintext, aad).unwrap();

        // Try to decrypt with different AAD
        let result = aead.open(&nonce, &ciphertext, b"Wrong AAD");
        assert\!(result.is_err());
    }

    #[test]
    fn test_aead_rfc8439_vectors() {
        // RFC 8439 ChaCha20-Poly1305 test vectors
        let key = hex::decode("...").unwrap();
        let nonce = hex::decode("...").unwrap();
        let plaintext = hex::decode("...").unwrap();
        let aad = hex::decode("...").unwrap();
        let expected_ciphertext = hex::decode("...").unwrap();

        let aead = Aead::new(AeadAlgorithm::ChaCha20Poly1305, &key).unwrap();
        let nonce = Nonce::from_bytes(&nonce).unwrap();
        let ciphertext = aead.seal(&nonce, &plaintext, &aad).unwrap();

        assert_eq\!(ciphertext, expected_ciphertext);
    }
}
```

### 4. HKDF Tests

```rust
#[cfg(test)]
mod hkdf_tests {
    use fcp_crypto::hkdf::{Hkdf, HkdfAlgorithm};

    #[test]
    fn test_hkdf_rfc5869_vectors() {
        // RFC 5869 Test Case 1
        let ikm = hex::decode("0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b0b").unwrap();
        let salt = hex::decode("000102030405060708090a0b0c").unwrap();
        let info = hex::decode("f0f1f2f3f4f5f6f7f8f9").unwrap();
        let expected_okm = hex::decode(
            "3cb25f25faacd57a90434f64d0362f2a2d2d0a90cf1a5a4c5db02d56ecc4c5bf34007208d5b887185865"
        ).unwrap();

        let hkdf = Hkdf::new(HkdfAlgorithm::Sha256, Some(&salt), &ikm);
        let mut okm = vec\![0u8; 42];
        hkdf.expand(&info, &mut okm).unwrap();

        assert_eq\!(okm, expected_okm);
    }

    #[test]
    fn test_hkdf_deterministic() {
        let ikm = b"input key material";
        let salt = b"salt value";
        let info = b"context info";

        let hkdf = Hkdf::new(HkdfAlgorithm::Sha256, Some(salt), ikm);
        let mut okm1 = [0u8; 32];
        let mut okm2 = [0u8; 32];

        hkdf.expand(info, &mut okm1).unwrap();
        hkdf.expand(info, &mut okm2).unwrap();

        assert_eq\!(okm1, okm2);
    }
}
```

### 5. Shamir Secret Sharing Tests

```rust
#[cfg(test)]
mod shamir_tests {
    use fcp_crypto::shamir::{ShamirSecretSharing, Share};

    #[test]
    fn test_shamir_threshold_reconstruction() {
        let secret = b"my-secret-key-32-bytes-exactly\!";
        let threshold = 3;
        let total_shares = 5;

        let sss = ShamirSecretSharing::new(threshold);
        let shares = sss.split(secret, total_shares).unwrap();

        assert_eq\!(shares.len(), total_shares);

        // Reconstruct with exactly threshold shares
        let subset: Vec<_> = shares.into_iter().take(threshold).collect();
        let recovered = sss.reconstruct(&subset).unwrap();

        assert_eq\!(recovered, secret);
    }

    #[test]
    fn test_shamir_insufficient_shares_fails() {
        let secret = b"secret-data";
        let threshold = 3;
        let total_shares = 5;

        let sss = ShamirSecretSharing::new(threshold);
        let shares = sss.split(secret, total_shares).unwrap();

        // Try with fewer than threshold shares
        let insufficient: Vec<_> = shares.into_iter().take(threshold - 1).collect();
        let result = sss.reconstruct(&insufficient);

        // Should fail or return incorrect value
        assert\!(result.is_err() || result.unwrap() \!= secret);
    }

    #[test]
    fn test_shamir_any_k_shares_work() {
        let secret = b"test-secret";
        let threshold = 3;
        let total_shares = 5;

        let sss = ShamirSecretSharing::new(threshold);
        let shares = sss.split(secret, total_shares).unwrap();

        // Test all possible k-subsets
        for combo in shares.iter().combinations(threshold) {
            let subset: Vec<_> = combo.into_iter().cloned().collect();
            let recovered = sss.reconstruct(&subset).unwrap();
            assert_eq\!(recovered, secret);
        }
    }
}
```

### 6. X25519 Key Exchange Tests

```rust
#[cfg(test)]
mod x25519_tests {
    use fcp_crypto::x25519::{X25519KeyPair, X25519PublicKey};

    #[test]
    fn test_x25519_key_agreement() {
        let alice = X25519KeyPair::generate();
        let bob = X25519KeyPair::generate();

        let alice_shared = alice.diffie_hellman(&bob.public_key());
        let bob_shared = bob.diffie_hellman(&alice.public_key());

        assert_eq\!(alice_shared, bob_shared);
    }

    #[test]
    fn test_x25519_rfc7748_vectors() {
        // RFC 7748 Section 6.1 test vectors
        let alice_private = hex::decode("...").unwrap();
        let bob_public = hex::decode("...").unwrap();
        let expected_shared = hex::decode("...").unwrap();

        let alice = X25519KeyPair::from_bytes(&alice_private).unwrap();
        let bob_pk = X25519PublicKey::from_bytes(&bob_public).unwrap();

        let shared = alice.diffie_hellman(&bob_pk);
        assert_eq\!(shared.as_bytes(), expected_shared.as_slice());
    }
}
```

## Golden Vectors

Store reference test data in `crates/fcp-crypto/tests/vectors/`:

- `cose/rfc8152_sign1_vector.cbor` - RFC 8152 COSE_Sign1 test cases
- `ed25519/wycheproof.json` - Wycheproof Ed25519 vectors
- `aead/rfc8439_chacha20poly1305.json` - RFC 8439 ChaCha20-Poly1305 vectors
- `hkdf/rfc5869.json` - RFC 5869 HKDF vectors
- `x25519/rfc7748.json` - RFC 7748 X25519 vectors

## Logging Requirements (per 1n78.35)

All test runs MUST emit structured JSONL:

```json
{"ts":"2026-01-28T12:00:00.000Z","level":"DEBUG","component":"crypto.test","event":"keygen","algorithm":"Ed25519","key_id":"pk_abc123"}
{"ts":"2026-01-28T12:00:00.001Z","level":"DEBUG","component":"crypto.test","event":"sign","algorithm":"EdDSA","payload_bytes":32}
{"ts":"2026-01-28T12:00:00.002Z","level":"INFO","component":"crypto.test","event":"verify","result":"valid","duration_ns":15000}
```

## Success Criteria

- [ ] All unit tests pass with `cargo test --package fcp-crypto`
- [ ] Wycheproof Ed25519 vectors pass 100%
- [ ] RFC test vectors match expected outputs exactly
- [ ] No timing side-channels in signature verification (constant-time)
- [ ] Key material is zeroized on drop

## Goal
Comprehensive test coverage for batch invoke functionality including zone constraints.

## Unit Tests

```rust
#[tokio::test]
async fn test_batch_invoke_parallel_execution() {
    // Independent ops run in parallel
    let harness = TestHarness::new().await;
    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation { id: "op1".into(), tool: "test.echo".into(), input: json!({"delay_ms": 100}), depends_on: vec![] },
            BatchOperation { id: "op2".into(), tool: "test.echo".into(), input: json!({"delay_ms": 100}), depends_on: vec![] },
        ],
        options: BatchOptions { max_parallelism: 5, stop_on_first_error: false, timeout: Duration::from_secs(30) },
    };

    let start = Instant::now();
    let response = harness.batch_invoke(batch).await.unwrap();
    let elapsed = start.elapsed();

    // Should complete in ~100ms, not 200ms (parallel)
    assert!(elapsed.as_millis() < 150);
    assert_eq!(response.completed, 2);
}

#[tokio::test]
async fn test_batch_invoke_dependency_ordering() {
    // op2 depends on op1, must run after
    let harness = TestHarness::new().await;
    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation { id: "op1".into(), tool: "test.set_state".into(), input: json!({"key": "x", "value": 1}), depends_on: vec![] },
            BatchOperation { id: "op2".into(), tool: "test.get_state".into(), input: json!({"key": "x"}), depends_on: vec!["op1".into()] },
        ],
        options: BatchOptions::default(),
    };

    let response = harness.batch_invoke(batch).await.unwrap();
    assert_eq!(response.results[1].output["value"], 1);
}

#[tokio::test]
async fn test_batch_invoke_partial_failure() {
    // Second op fails, first succeeds
    let harness = TestHarness::new().await;
    let batch = BatchInvokeRequest {
        operations: vec![
            BatchOperation { id: "op1".into(), tool: "test.echo".into(), input: json!({}), depends_on: vec![] },
            BatchOperation { id: "op2".into(), tool: "test.fail".into(), input: json!({}), depends_on: vec![] },
        ],
        options: BatchOptions { stop_on_first_error: false, ..Default::default() },
    };

    let response = harness.batch_invoke(batch).await.unwrap();
    assert_eq!(response.status, "partial_success");
    assert_eq!(response.completed, 1);
    assert_eq!(response.failed, 1);
}

