        let hint = MissingHint::from_indices(&missing);

        let status = DecodeStatus {
            object_id: object_id.clone(),
            symbols_received: 147,
            symbols_required: 150,
            missing_hint: Some(hint),
        };

        // Receiver can use hint for targeted repair
        assert!(status.has_missing_hint());
        assert_eq!(status.missing_indices(), vec![42, 67, 89]);
    }

