        let status = DecodeStatus {
            object_id: object_id.clone(),
            symbols_received: 147,
            symbols_required: 150,
            missing_hint: Some(MissingHint::from_indices(&[42, 67, 89])),
        };

        let repair_response = handler.handle_decode_status(status);

        // Should send only missing symbols, not flood
        assert_eq!(repair_response.symbols.len(), 3);
