```rust
#[cfg(test)]
mod ack_tests {
    use fcp_sdk::streaming::{AckTracker, AckResult, EventEnvelope};
    use std::time::Duration;

    #[test]
    fn test_ack_tracking_basic() {
        let tracker = AckTracker::new();

        let envelope = EventEnvelope::builder()
            .seq(1)
            .cursor("c1")
            .requires_ack(true)
            .build();

        tracker.track(&envelope);
        assert\!(tracker.is_pending("c1"));

        tracker.ack("c1").unwrap();
        assert\!(\!tracker.is_pending("c1"));
    }

    #[test]
    fn test_ack_idempotent() {
        let tracker = AckTracker::new();
        let envelope = EventEnvelope::ack_required("test", 1, "c1");
        tracker.track(&envelope);

        // First ack succeeds
        assert\!(tracker.ack("c1").is_ok());

        // Second ack is idempotent (not an error)
        assert\!(tracker.ack("c1").is_ok());
    }

    #[test]
    fn test_ack_unknown_cursor_error() {
        let tracker = AckTracker::new();

        // Ack for unknown cursor should fail
        let result = tracker.ack("unknown_cursor");
        assert\!(matches\!(result, Err(AckError::UnknownCursor(_))));
    }

    #[test]
    fn test_ack_timeout_redelivery() {
        let tracker = AckTracker::with_timeout(Duration::from_millis(100));

        let envelope = EventEnvelope::ack_required("test", 1, "c1");
        tracker.track(&envelope);

        // Wait for timeout
        std::thread::sleep(Duration::from_millis(150));

        // Event should be marked for redelivery
        let pending = tracker.pending_redelivery();
        assert_eq\!(pending.len(), 1);
        assert_eq\!(pending[0].cursor, "c1");
    }

    #[test]
    fn test_batch_ack() {
        let tracker = AckTracker::new();

        for i in 1..=10 {
            let envelope = EventEnvelope::ack_required("test", i, format\!("c{i}"));
            tracker.track(&envelope);
        }

        // Batch ack cursors 1-5
        let cursors: Vec<_> = (1..=5).map(|i| format\!("c{i}")).collect();
        let result = tracker.batch_ack(&cursors);
        assert_eq\!(result.acked, 5);
        assert_eq\!(result.failed, 0);

        assert_eq\!(tracker.pending_count(), 5); // 6-10 still pending
    }
}
